using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_StartsWithAreaCodeInParens()
    {
        string result = _formatter.FormatPhoneNumber("8005559999");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("8005559999");

        StringAssert.EndsWith(result, "-9999");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_ContainsSeparatorDash()
    {
        string result = _formatter.FormatPhoneNumber("3125550000");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_MatchesExpectedPattern()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_NameOnly_ReturnsDefaultTitle()
    {
        string result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_Result_StartsWithDear()
    {
        string result = _formatter.BuildGreeting("Doe");

        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_Result_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Doe");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_Result_ContainsName()
    {
        string result = _formatter.BuildGreeting("Anderson", "Ms.");

        StringAssert.Contains(result, "Anderson");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StripsNonAlphanumeric()
    {
        string result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        string result = _formatter.GenerateSlug("My Article Title 2024");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_AreTrimmed()
    {
        string result = _formatter.GenerateSlug("  padded title  ");

        StringAssert.StartsWith(result, "padded");
        StringAssert.EndsWith(result, "title");
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_IsLowered()
    {
        string result = _formatter.GenerateSlug("UPPER lower MiXeD");

        StringAssert.DoesNotMatch(result, new System.Text.RegularExpressions.Regex(@"[A-Z]"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_PrependsDollarSign()
    {
        string result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_PrependsSymbol()
    {
        string result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWith00()
    {
        string result = _formatter.FormatCurrency(50m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_FormatsCorrectly()
    {
        string result = _formatter.FormatCurrency(1234.56m);

        Assert.AreEqual("$1234.56", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        string result = _formatter.FormatCurrency(-5.00m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_FormatsAsZero()
    {
        string result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_Result_MatchesCurrencyPattern()
    {
        string result = _formatter.FormatCurrency(42.10m, "£");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^.+\d+\.\d{2}$"));
    }
}

