12.     [TestMethod]
13.     public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
14.     {
15.         string result = _formatter.FormatPhoneNumber("2125551234");
16. 
17.         Assert.AreEqual("(212) 555-1234", result);
18.     }
19. 
